const navLinks = [
  { label: "Commencement", href: "/commencement/" },
  { label: "Showcase", href: "/showcase/" },
  { label: "Thesis Exhibitions", href: "/thesis/" },
  { label: "Students", href: "/students/" },
];

const currentPath = Astro.url.pathname;
---

<header class="site-header">
  <div class="header-inner container">
    <a href="/" class="site-logo">CCA 2026</a>
    <nav aria-label="Main navigation">
      <details class="mobile-nav">
        <summary aria-label="Toggle menu">
          <span class="menu-icon" aria-hidden="true"></span>
        </summary>
        <ul class="nav-list" role="list">
          {navLinks.map\(\(link\) => \(
            <li>
              <a
                href={link.href}
                aria-current={currentPath.startsWith\(link.href\) ? "page" : undefined}
              >
                {link.label}
              </a>
            </li>
          \)\)}
        </ul>
      </details>
      <ul class="nav-list desktop-nav" role="list">
        {navLinks.map\(\(link\) => \(
          <li>
            <a
              href={link.href}
              aria-current={currentPath.startsWith\(link.href\) ? "page" : undefined}
            >
              {link.label}
            </a>
          </li>
        \)\)}
      </ul>
    </nav>
  </div>
</header>

<style>
  .site-header {
    position: sticky;
    top: 0;
    z-index: 100;
    background: var\(--color-bg\);
    border-bottom: 1px solid var\(--color-border\);
  }

  .header-inner {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding-block: var\(--space-4\);
  }

  .site-logo {
    font-family: var\(--font-heading\);
    font-weight: 700;
    font-size: var\(--text-lg\);
    text-decoration: none;
    color: var\(--color-text\);
  }

  .nav-list {
    list-style: none;
    display: flex;
    gap: var\(--space-6\);
    padding: 0;
    margin: 0;
  }

  .nav-list a {
    font-size: var\(--text-sm\);
    text-decoration: none;
    color: var\(--color-text\);
    transition: color 0.2s ease;
  }

  .nav-list a:hover,
  .nav-list a[aria-current="page"] {
