---
import type { CollectionEntry } from "astro:content";
import { formatDate, formatDateRange } from "../../lib/utils/format";

interface Props {
  event: CollectionEntry<"events">;
}

const { event } = Astro.props;
const { title, date, endDate, location, description, type, degreeLevel, themeKey } = event.data;

function getEventUrl\(type: string, degreeLevel: string\): string {
  const typeMap: Record<string, string> = {
    commencement: "/commencement/",
    showcase: "/showcase/",
    "thesis-exhibition": "/thesis/",
  };
  const base = typeMap[type] ?? "/";
  if \(degreeLevel === "all"\) return base;
  return `${base}${degreeLevel}/`;
}

const href = getEventUrl\(type, degreeLevel\);
const dateDisplay = endDate ? formatDateRange\(date, endDate\) : formatDate\(date\);
---

<a href={href} class="event-card" data-theme={themeKey}>
  <article>
    <h3 class="event-title">{title}</h3>
    <time class="event-date">{dateDisplay}</time>
    <p class="event-location">{location}</p>
    <p class="event-desc">{description}</p>
  </article>
</a>

<style>
  .event-card {
    display: block;
    text-decoration: none;
    color: var\(--color-text\);
    background: var\(--color-surface\);
    border: 1px solid var\(--color-border\);
    border-left: 4px solid var\(--color-accent\);
    padding: var\(--space-6\);
    transition: border-color 0.2s ease, box-shadow 0.2s ease;
  }

  .event-card:hover {
    border-left-color: var\(--color-accent\);
    box-shadow: 0 2px 8px rgba\(0, 0, 0, 0.08\);
  }

  .event-title {
    font-size: var\(--text-xl\);
    margin-bottom: var\(--space-2\);
  }

  .event-date {
    display: block;
    font-size: var\(--text-sm\);
    color: var\(--color-accent\);
    margin-bottom: var\(--space-1\);
  }

  .event-location {
    font-size: var\(--text-sm\);
    color: var\(--color-muted\);
    margin-bottom: var\(--space-3\);
  }

  .event-desc {
    font-size: var\(--text-sm\);
    color: var\(--color-muted\);
  }
</style>
